import { NextRequest, NextResponse } from "next/server";
import formidable from "formidable";
import { db } from "@/lib/db";
import fs from "fs/promises";
import path from "path";

export const config = { api: { bodyParser: false } };

export async function POST(req: NextRequest) {
  try {
    const form = formidable({ multiples: false, keepExtensions: true });

    const [fields, files] = await new Promise((resolve, reject) => {
      form.parse(req, (err, fields, files) => {
        if (err) reject(err);
        else resolve([fields, files]);
      });
    });

    console.log("fields : ", fields);
    

    const { id, name, email, phone_number } = fields;

    if (!id) {
      return NextResponse.json(
        { error: "User ID is required" },
        { status: 400 }
      );
    }

    const uploadDir = "./public/uploads/";
    await fs.mkdir(uploadDir, { recursive: true });

    const saveFile = async (file) => {
      if (!file) return null;
      const newPath = path.join(uploadDir, file.originalFilename);
      await fs.rename(file.filepath, newPath);
      return `/uploads/${file.originalFilename}`;
    };

    const tenth_certificate = await saveFile(files.tenth_certificate);
    const twelfth_certificate = await saveFile(files.twelfth_certificate);

    await db.query(
      "UPDATE users SET name=?, email=?, phone_number=?, tenth_certificate=?, twelfth_certificate=? WHERE id=?",
      [name, email, phone_number, tenth_certificate, twelfth_certificate, id]
    );

    return NextResponse.json({ message: "Profile updated successfully" });
  } catch (error) {
    console.error("Error updating profile:", error);
    return NextResponse.json(
      { error: "Failed to update profile" },
      { status: 500 }
    );
  }
}
